def serialize(config, path):
    with open(path, 'w') as file:
        # Write section comments
        if hasattr(config, 'comments') and 'header' in config.comments:
            file.write(f"# {config.comments['header']}\n")
        for section in config.sections():
            if hasattr(config, 'comments') and section in config.comments:
                file.write(f"\n# {config.comments[section]}\n")
            file.write(f"[{section}]\n")
            for key, value in config.items(section):
                if hasattr(config, 'comments') and f"{section}.{key}" in config.comments:
                    file.write(f"# {config.comments[f'{section}.{key}']}\n")
                file.write(f"{key} = {value}\n")

